def get_statistical_catalog() -> list[dict[str, object]]:
    return [*STATISTICAL_METHODS, *EXTENDED_STATISTICAL_METHOD_CARDS]


def get_catalog_summary() -> dict[str, object]:
    methods = get_statistical_catalog()
    family_counts = Counter(item["family"] for item in methods)
    status_counts = Counter(item["status"] for item in methods)
    return {
        "total_methods": len(methods),
        "live_methods": status_counts.get("live", 0),
        "catalog_methods": status_counts.get("catalog", 0),
        "families": dict(sorted(family_counts.items())),
    }
